import { Divider } from "antd";
import { useEffect, useState } from "react";
import SpinCustom from "src/components/SpinCustom";
import PaidListTable from "src/pages/USER/MembershipFees/components/PaidListTable";
import SupportSection from "src/pages/USER/MembershipFees/components/SupportSection";
import AssociationService from "src/services/AssociationService";
import "./style.scss";

const PaymentHistory = () => {
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // Nếu cần load chi hội để hiển thị trong nơi khác, giữ lại
    const fetchChapters = async () => {
      try {
        setLoading(true);
        await AssociationService.getMyAssociationList();
      } catch (error) {
        console.error("Error fetching chapters", error);
      } finally {
        setLoading(false);
      }
    };

    fetchChapters();
  }, []);

  return (
    <div className="membership-fee-manager">
      <SpinCustom spinning={loading}>
        <div className="fee-tab-section">
          <PaidListTable />
        </div>
      </SpinCustom>

      <Divider />
      <SupportSection />
    </div>
  );
};

export default PaymentHistory;
