import { SearchOutlined } from "@ant-design/icons"
import { Col, Empty, Row, Typography, Collapse } from "antd"
import dayjs from "dayjs"
import { useEffect, useMemo, useState } from "react"
import InputCustom from "src/components/Input/InputCustom"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import FeeManagement from "src/services/FeeManagement"
import AssociationService from "src/services/AssociationService"
import "../styles/PaidListTable.scss"

const { Text } = Typography
const { Panel } = Collapse

const PaidListTable = () => {
  const [listData, setListData] = useState([])
  const [loading, setLoading] = useState(false)
  const [searchKeyword, setSearchKeyword] = useState("")
  const [selectedYear, setSelectedYear] = useState("all")
  const [listAssociation, setListAssociation] = useState([])

  const getListAssociation = async () => {
    try {
      const res = await AssociationService.getMyAssociationList()
      if (res?.isError) return
      setListAssociation(res?.Object || [])
    } catch (error) {
      console.error("Error fetching associations:", error)
    }
  }

  const getAssociationName = id => {
    const found = listAssociation.find(a => a.AssociationID === id)
    return found?.AssociationName || "Không xác định"
  }

  const getList = async () => {
    try {
      setLoading(true)
      const res = await FeeManagement.getMyFeeAssignment({
        PaymentStatus: 2,
      })
      if (res?.isError) return
      const data =
        res?.Object?.map(item => ({
          ...item,
          key: item.FeeAssignmentID,
        })) || []
      setListData(data)
    } catch (error) {
      console.error("Error fetching paid data:", error)
    } finally {
      setLoading(false)
    }
  }

  const filteredData = useMemo(() => {
    return listData
      .filter(item =>
        selectedYear === "all"
          ? true
          : dayjs(item.PaidDate).year().toString() === selectedYear,
      )
      .filter(item =>
        (getAssociationName(item.AssociationID) || "")
          .toLowerCase()
          .includes(searchKeyword.toLowerCase()),
      )
  }, [listData, searchKeyword, selectedYear, listAssociation])

  const totalAmount = useMemo(
    () =>
      filteredData.reduce((sum, item) => sum + Number(item.PaidAmount || 0), 0),
    [filteredData],
  )

  const yearOptions = useMemo(() => {
    const years = [
      ...new Set(listData.map(item => dayjs(item.PaidDate).year().toString())),
    ]
    return years.sort((a, b) => b - a)
  }, [listData])

  const groupedByMonth = useMemo(() => {
    const map = {}
    filteredData.forEach((item) => {
      const key = dayjs(item.PaidDate).format("MM/YYYY")
      if (!map[key]) map[key] = []
      map[key].push(item)
    })
    return Object.entries(map).sort(
      ([a], [b]) => dayjs(b, "MM/YYYY").valueOf() - dayjs(a, "MM/YYYY").valueOf()
    )
  }, [filteredData])

  useEffect(() => {
    getList()
    getListAssociation()
  }, [])

  return (
    <SpinCustom spinning={loading}>
      <div
        className="paid-list-table-v2"
        style={{ background: "#fff", padding: 16, borderRadius: 8 }}
      >
        <Row gutter={[16, 16]} className="mb-6">
          <Col span={12}>
            <InputCustom
              allowClear
              placeholder="Tìm kiếm theo chi hội"
              onChange={e => setSearchKeyword(e.target.value)}
              prefix={<SearchOutlined style={{ color: "#bfbfbf" }} />}
            />
          </Col>
          <Col span={12}>
            <SelectCustom
              value={selectedYear}
              onChange={setSelectedYear}
              options={[
                { value: "all", label: "Tất cả các năm" },
                ...yearOptions.map(y => ({
                  value: y,
                  label: y,
                })),
              ]}
            />
          </Col>
        </Row>

        {filteredData.length === 0 ? (
          <Empty
            description="Không tìm thấy giao dịch nào"
            imageStyle={{ height: 120 }}
            style={{ marginTop: 40 }}
          />
        ) : (
          <Collapse accordion>
            {groupedByMonth.map(([month, items]) => (
              <Panel header={`Tháng ${month}`} key={month}>
                {items.map((item, index) => (
                  <div key={item.key || index} className="transaction-item">
                    <div className="item-header">
                      <Text className="date">{dayjs(item.PaidDate).format("DD/MM/YYYY")}</Text>
                      <Text className="amount">-{Number(item.PaidAmount).toLocaleString()} ₫</Text>
                    </div>
                    <div className="item-body">
                      <Text className="note">{item.Note || "Không có nội dung"}</Text>
                      <Text className="chapter">{getAssociationName(item.AssociationID)}</Text>
                    </div>
                  </div>
                ))}
              </Panel>
            ))}
          </Collapse>
        )}

        <div style={{ textAlign: "right", marginTop: 16 }}>
          <Text strong>Tổng đã đóng: </Text>
          <Text strong style={{ color: "red" }}>
            {totalAmount.toLocaleString()} ₫
          </Text>
        </div>
      </div>
    </SpinCustom>
  )
}

export default PaidListTable
